  async getAllTasks(req: Request, res: Response) {
    const client = await this.pool.connect();
    try {
      const userId = req.user?.id;

      if (!userId) {
        res.status(401).json({error: 'User not authenticated'});
        return;
      }

      const result = await client.query<Task>(`
        SELECT t.*,
               COUNT(th.id)                                      as total_runs,
               COUNT(CASE WHEN th.status = 'success' THEN 1 END) as successful_runs,
               MAX(th.end_time)                                  as last_completed
        FROM tasks t
               LEFT JOIN task_history th ON t.id = th.task_id
        WHERE t.user_id = $1
        GROUP BY t.id
        ORDER BY t.created_at DESC
      `, [userId]);

      res.json(result.rows);
    } catch (error) {
      logger.error('Error fetching tasks:', error);
      res.status(500).json({error: 'Failed to fetch tasks'});
    } finally {
      client.release();
    }
  }

  async getTaskById(req: Request, res: Response) {
    const client = await this.pool.connect();
    try {
      const userId = req.user?.id;
      const taskId = parseInt(req.params.id);

      if (!userId) {
        res.status(401).json({error: 'User not authenticated'});
        return;
      }

      const result = await client.query(`
        SELECT t.*,
               COUNT(th.id)                                      as total_runs,
               COUNT(CASE WHEN th.status = 'success' THEN 1 END) as successful_runs,
               MAX(th.end_time)                                  as last_completed
        FROM tasks t
               LEFT JOIN task_history th ON t.id = th.task_id
        WHERE t.id = $1
          AND t.user_id = $2
        GROUP BY t.id
      `, [taskId, userId]);

      if (result.rows.length === 0) {
        res.status(404).json({error: 'Task not found'});
        return;
      }

      res.json(result.rows[0]);
    } catch (error) {
      logger.error('Error fetching task:', error);
      res.status(500).json({error: 'Failed to fetch task'});
    } finally {
      client.release();
    }
  }

  async createTask(req: Request, res: Response) {
    const client = await this.pool.connect();
    try {
      const userId = req.user?.id;

      if (!userId) {
        res.status(401).json({error: 'User not authenticated'});
        return;
      }

      const taskData: CreateTaskRequest = {
        ...req.body,
        channel_ids: req.body.channel_ids || [],
        game_ids: req.body.game_ids || [],
